// Java 25 exam prep - Optional lazy fallback
// Learn: use orElseGet when fallback work should run only for empty Optional.
import java.util.Optional;
import java.util.function.Supplier;

static String buildGuestName() {
  // This fallback should run only when the Optional is empty.
  return "guest";
}

Optional<String> nickname = Optional.of("Ada");
Supplier<String> fallback = () -> buildGuestName();
String displayName = nickname
  .filter(name -> name.length() > 2)
  .orElseGet(fallback);
System.out.println(displayName);
